#include <torch/library.h>
#include <torch/extension.h>
#include "pytorch_npu_helper.hpp"

// Helper to permute tensor so that the given dimension becomes last
static at::Tensor permute_to_last_dim(const at::Tensor& self, int64_t dim) {
    int64_t ndim = self.dim();
    dim = (dim + ndim) % ndim;  // handle negative
    std::vector<int64_t> perm;
    for (int64_t i = 0; i < ndim; ++i) {
        if (i != dim) perm.push_back(i);
    }
    perm.push_back(dim);
    return self.permute(perm);
}

static at::Tensor permute_back(const at::Tensor& self, int64_t dim, int64_t ndim) {
    // input self has last dim reduced (removed), original shape had dim at last
    // We need to permute back: move the last dim to its original position.
    // But after reduction, output has ndim-1 dimensions. The original dim is now last in the permuted shape.
    // The permuted shape order is: all dims except dim, then dim. So to restore, we need to permute the output
    // so that the original dim's position is dim, and the rest follow in original order.
    std::vector<int64_t> perm;
    for (int64_t i = 0; i < ndim - 1; ++i) {
        if (i < dim) perm.push_back(i);
        else perm.push_back(i + 1);  // skip the last index which was the original dim
    }
    perm.insert(perm.begin() + dim, ndim - 1);  // last dim goes to position dim
    return self.permute(perm);
}

at::Tensor argmax_impl_npu(const at::Tensor& self, int64_t dim) {
    // Permute so that reduction dim becomes last
    at::Tensor permuted = permute_to_last_dim(self, dim);
    // Prepare output tensor (shape: all dims except last)
    std::vector<int64_t> out_shape;
    int64_t ndim = permuted.dim();
    for (int64_t i = 0; i < ndim - 1; ++i) {
        out_shape.push_back(permuted.size(i));
    }
    at::Tensor result = at::empty(out_shape, permuted.options().dtype(at::kLong));
    // Call custom AscendC operator (aclnn)
    EXEC_NPU_CMD(aclnnArgmaxOverADimensionCustom, permuted, result);
    // Permute result back to original order
    int64_t orig_ndim = self.dim();
    return permute_back(result, dim, orig_ndim);
}

TORCH_LIBRARY_IMPL(myops, PrivateUse1, m) {
    m.impl("argmax_over_a_dimension_custom", &argmax_impl_npu);
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("argmax_over_a_dimension_custom", &argmax_impl_npu, "Argmax over a dimension (AscendC custom)");
